const e=`{% block sw_confirm_modal %} <sw-modal class="sw-confirm-modal" v-bind="$attrs" :variant="variant" :title="titleText" @modal-close="$emit('close')" > {% block sw_confirm_modal_text %} <slot> {% block sw_confirm_modal_text_default %} <p class="sw-confirm-modal__text"> {{ descriptionText }} </p> {% endblock %} </slot> {% endblock %} {% block sw_confirm_modal_footer %} <template #modal-footer> {% block sw_confirm_modal_footer_cancel %} <mt-button class="sw-confirm-modal__button-cancel" size="small" variant="secondary" @click="$emit('cancel')" > {{ cancelText }} </mt-button> {% endblock %} {% block sw_confirm_modal_footer_confirm %} <mt-button class="sw-confirm-modal__button-confirm" :variant="confirmButtonVariant" size="small" @click="$emit('confirm')" > {{ confirmText }} </mt-button> {% endblock %} </template> {% endblock %} </sw-modal> {% endblock %}`,l={template:e,emits:["close","cancel","confirm"],props:{title:{type:String,required:!1,default:""},text:{type:String,required:!1,default:""},textConfirm:{type:String,required:!1,default:""},variant:{type:String,required:!1,default:"small",validValues:["default","small","large","full"],validator(t){return t.length?["default","small","large","full"].includes(t):!0}},type:{type:String,required:!1,default:"confirm",validValues:["confirm","delete","yesno","discard"],validator(t){return t.length?["confirm","delete","yesno","discard"].includes(t):!0}}},computed:{titleText(){return this.title!==null&&this.title.length>0?this.title:this.$t("global.default.warning")},descriptionText(){return this.text!==null&&this.text.length>0?this.text:this.$t("sw-confirm-modal.defaultText")},confirmText(){if(this.textConfirm)return this.textConfirm;switch(this.type){case"delete":return this.$t("global.default.delete");case"yesno":return this.$t("global.default.yes");case"discard":return this.$t("global.default.discard");default:return this.$t("global.default.confirm")}},cancelText(){return this.type==="yesno"?this.$t("global.default.no"):this.$t("global.default.cancel")},confirmButtonVariant(){switch(this.type){case"delete":case"discard":return"critical";default:return"primary"}}}};export{l as default};
